mapper.insert:
insert ignore into custom_model(model_no, eu_size, type) value (
    #{modelNo},
    #{euSize},
    #{type}
)

mapper.select:
select count(*) from custom_model
where type = #{type}

    and model_no like concat('%', #{modelNo}, '%')

select * from custom_model
where type = #{type}

    and model_no like concat('%', #{modelNo}, '%')

order by model_no, eu_size
limit #{startIndex}, #{pageSize}

mapper.delete:
delete from custom_model
where type = #{type} and model_no = #{modelNo}

    and eu_size = #{euSize}


    and (eu_size is null or eu_size = '')
